#include <iostream>

void countdown(int value, int depth)
{
    std::cout << "[depth " << depth << "] countdown(" << value << ")\n";

    if (value == 0)
    {
        std::cout << "[depth " << depth << "] base case reached\n";
        return;
    }

    countdown(value - 1, depth + 1);
}

int main()
{
    int n{};
    std::cin >> n;
    countdown(n, 1);
    return 0;
}
